# Load pre-trained model
tokenizer = AutoTokenizer.from_pretrained("T5-base")
model = AutoModelForSeq2SeqLM.from_pretrained("T5-base")

# Initialize Faiss vector database
vector_db = faiss.StandardGpuResources()
faiss_index = faiss.IndexFlatL2(vector_dim=768) # 768 is the hidden size of T5-base model
faiss_index.resize(1, 100000)
faiss.gpu(0).reset_memories()

# Load documents into vector database
def load_documents(documents):
    all_encodings = []
    for doc in documents:
        encoding = tokenizer.encode_pad(doc, padding=True, truncation=True, max_length=512)
        with torch.no_grad():
            input_ids = torch.tensor([encoding])
            output = model(**{"input_ids": input_ids})[0]
        all_encodings.append(output[0][:, 0, :].cpu().numpy())
    return all_encodings

# Save and load vector database
def save_index(index, filename):
    with open(filename, "wb") as f:
        faiss.serialization.write_index(faiss.vector_norm(index.index, 2), f)

def load_index(filename):
    with open(filename, "rb") as f:
        index = faiss.serialization.read_index(f)
    return index

# Function to perform search and generate response
def search_and_generate(query, index, top_k=5):
    query_encoding = tokenizer.encode_pad([query], padding=True, truncation=True, max_length=512)[0]
    query_encoding = torch.tensor([query_encoding])
    with torch.no_grad():
        output = model(**{"input_ids": query_encoding})[0]
        query_vector = output[0][:, 0, :].cpu().numpy()

    _, indices = faiss.nn.search(query_vector, index, top_k)
    retrived_documents = [index.index.data[i] for i in indices[0]]
    retrived_document_ids = [doc[0] for doc in retrived_documents]

    # Get the text of retrieved documents and concatenate them to the query as inputs to generate response
    all_texts = []
    for document_id in retrived_document_ids:
        all_texts.append(documents[document_id])
    all_texts.append(query)
    input_ids = tokenizer.batch_encode_plus(all_texts, padding=True, truncation=True, max_length=512)[ "input_ids"][0]

    # Generate response
    output = model(**{"input_ids": input_ids})[0][:, 1024:]
    response = tokenizer.decode(output.argmax(dim=-1))

    return response

